const outputText = $input.all()[0].json.output;

let questions = [];

try {
  // Clean up markdown if AI accidentally includes it
  let cleanText = outputText.replace(/```json/g, '').replace(/```/g, '').trim();
  questions = JSON.parse(cleanText);
} catch (e) {
  console.error("JSON Parse Error", e);
  // Fallback to empty if critical failure
  questions = [];
}

// Ensure structure consistency
const validatedQuestions = Array.isArray(questions) ? questions.map(q => ({
  question: q.question || "",
  type: "Coding",
  difficulty: q.difficulty || "Medium",
  testCases: Array.isArray(q.testCases) ? q.testCases : []
})) : [];

return { questions: validatedQuestions };
